class e extends HTMLElement {
    constructor(e = {}) {
        super();
        this.config = {
            targetSelector: "img",
            maxScale: 5,
            minScale: 0.5,
            allowRotate: !0,
            allowDownload: !0,
            ...e,
        };
        this.currentScale = 1;
        this.currentRotation = 0;
        this.isDragging = !1;
        this.startX = 0;
        this.startY = 0;
        this.currentX = 0;
        this.currentY = 0;
        this.imageList = [];
        this.currentIndex = -1;
        // --- 触摸相关变量 ---
        this.touchStartCoords = { x: [], y: [] };
        this.lastPinchDistance = 0;
        this.isPinching = false;
        // --------------------
        this.attachShadow({ mode: "open" });
        this.#e();
    }

    #e() {
        this.shadowRoot.innerHTML = `<style>
#overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    /* 默认高度 */
    height: 100vh;
    background-color: rgba(255, 255, 255, 80%);
    display: none;
    justify-content: center;
    align-items: center;
    z-index: 999999;
    overflow: hidden;
    cursor: default;
    -webkit-user-select: none;
    -ms-user-select: none;
    user-select: none;
    /* 默认模糊 */
    backdrop-filter: blur(10px);
    opacity: 0;
    transform: scale(0.8);
    transition: opacity 0.25s ease, transform 0.25s ease;
}
/* 全屏模式下的覆盖层样式 */
#overlay.fullscreen-mobile {
    background-color: rgba(255, 255, 255, 80%);
    backdrop-filter: blur(10px);
    height: 100dvh; /* 使用 dvh 防止地址栏影响 */
}
#overlay.showing {
    opacity: 1;
    transform: scale(1);
}
#image-wrapper {
    position: relative;
    transform-origin: center center;
    transition: transform 0.1s ease-out;
    -webkit-user-select: none;
    -ms-user-select: none;
    user-select: none;
}
#preview-img {
    max-width: 90vw;
    max-height: 90vh;
    object-fit: contain;
    border-radius: 5px;
    cursor: grab;
    pointer-events: none;
    box-shadow: #000000b0 0px 30px 50px 0px;
}
#image-wrapper:active #preview-img,
#overlay.dragging #preview-img {
    cursor: grabbing;
}
#overlay.dragging {
    cursor: grabbing;
}
#loading {
    color: rgb(255, 107, 107);
    font-size: 2em;
}
#nav-controls {
    position: absolute;
    bottom: 75px;
    left: 0;
    width: 100%;
    display: flex;
    justify-content: space-between;
    transform: translateY(-50%);
    padding: 0 20px;
    box-sizing: border-box;
    z-index: 1;
    pointer-events: none;
}
.nav-btn {
    pointer-events: auto;
}
#controls {
    position: absolute;
    top: 20px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 10px;
    z-index: 10;
}
.control-btn, .nav-btn {
    background-color: rgb(255, 255, 255);
    color: #ff7d7d;
    border: none;
    border-radius: 50px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background-color 0.2s, transform 0.2s ease-out;
    -webkit-user-select: none;
    -ms-user-select: none;
    user-select: none;
    box-shadow: #ffb3b3 0px 0px 9px 0px;
}
.control-btn:hover, .nav-btn:hover {
    background-color: #88e688;
    transform: scale(1.1);
    box-shadow: #88e688 0px 0px 9px 0px;
    color: #fff;
}
.control-btn {
    width: 90px;
    height: 40px;
    font-size: 13px;
}
.nav-btn {
    width: 60px;
    height: 60px;
    font-size: 25px;
    font-weight: bold;
}
.nav-btn:disabled {
    background-color: rgba(255, 255, 255, 0);
    cursor: not-allowed;
    transform: none;
    color: #54545433;
    box-shadow: #0000001c 0px 0px 9px 0px;
}
#close-btn:hover {
    background-color: #ff0000;
    color: #fff;
    box-shadow: #ffb3b3 0px 0px 9px 0px;
}
#image-info {
    position: absolute;
    bottom: 30px;
    left: 50%;
    transform: translateX(-50%);
    background-color: rgb(255, 255, 255);
    color: rgb(255, 128, 128);
    padding: 10px 20px;
    border-radius: 25px;
    font-size: 16px;
    z-index: 10;
    max-width: 80%;
    text-align: center;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 15px;
    white-space: nowrap;
    box-shadow: #ff7e7e 0px 0px 12px;
}
#image-caption {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
    font-weight: bold;
}
#image-resolution, #image-zoom, #image-index {
    font-size: inherit;
    white-space: nowrap;
    color: #7dc77e;
}
@media (max-width: 768px) {
    #image-info {
        font-size: 14px;
        padding: 8px 16px;
    }
}
</style><div id="overlay">
    <div id="nav-controls">
        <button id="prev-btn" class="nav-btn" disabled>◀︎</button>
        <button id="next-btn" class="nav-btn" disabled>▶︎</button>
    </div>
    <div id="controls">
        <button id="download-btn" class="control-btn">⇣ 下载</button>
        <button id="rotate-btn" class="control-btn">↻ 旋转</button>
        <button id="close-btn" class="control-btn">x 关闭</button>
    </div>
    <div id="loading">加载中……</div>
    <div id="image-wrapper">
        <img id="preview-img" alt="Image Preview">
    </div>
    <div id="image-info">
        <span id="image-caption"></span>
        <span id="image-resolution"></span>
        <span id="image-zoom"></span>
        <span id="image-index"></span>
    </div>
</div>`;
    }

    connectedCallback() {
        this.#t();
        this.#i();
        this.#n();
        this.#s();
    }

    disconnectedCallback() {
        this.#o();
        this.#a();
        this.imageWrapper.removeEventListener("touchstart", this.handleTouchStart.bind(this));
        this.imageWrapper.removeEventListener("touchmove", this.handleTouchMove.bind(this));
        this.imageWrapper.removeEventListener("touchend", this.handleTouchEnd.bind(this));
        this.imageWrapper.removeEventListener("touchcancel", this.handleTouchEnd.bind(this));
        this.observer && this.observer.disconnect();
    }

    #t() {
        this.overlay = this.shadowRoot.getElementById("overlay");
        this.imageWrapper = this.shadowRoot.getElementById("image-wrapper");
        this.previewImg = this.shadowRoot.getElementById("preview-img");
        this.loadingIndicator = this.shadowRoot.getElementById("loading");
        this.closeBtn = this.shadowRoot.getElementById("close-btn");
        this.rotateBtn = this.shadowRoot.getElementById("rotate-btn");
        this.downloadBtn = this.shadowRoot.getElementById("download-btn");
        this.prevBtn = this.shadowRoot.getElementById("prev-btn");
        this.nextBtn = this.shadowRoot.getElementById("next-btn");
        this.imageCaption = this.shadowRoot.getElementById("image-caption");
        this.imageResolution = this.shadowRoot.getElementById("image-resolution");
        this.imageZoom = this.shadowRoot.getElementById("image-zoom");
        this.imageIndex = this.shadowRoot.getElementById("image-index");
        this.imageInfo = this.shadowRoot.getElementById("image-info");
    }

    #i() {
        this.targetSelector = this.config.targetSelector;
        this.config.allowRotate || (this.rotateBtn.style.display = "none");
        this.config.allowDownload || (this.downloadBtn.style.display = "none");
    }

    #n() {
        this.imageList = Array.from(document.querySelectorAll(this.targetSelector));
        this.observeImages();
        this.bindClickEvents(this.imageList);
    }

    #s() {
        this.overlay.addEventListener("wheel", this.handleWheel.bind(this));
        this.imageWrapper.addEventListener("mousedown", this.startDrag.bind(this));
        this.imageWrapper.addEventListener("touchstart", this.handleTouchStart.bind(this));
        this.imageWrapper.addEventListener("touchmove", this.handleTouchMove.bind(this));
        this.imageWrapper.addEventListener("touchend", this.handleTouchEnd.bind(this));
        this.imageWrapper.addEventListener("touchcancel", this.handleTouchEnd.bind(this));
        this.closeBtn.addEventListener("click", this.closePreview.bind(this));
        this.rotateBtn.addEventListener("click", this.rotateImage.bind(this));
        this.downloadBtn.addEventListener("click", this.downloadImage.bind(this));
        this.prevBtn.addEventListener("click", this.showPrevImage.bind(this));
        this.nextBtn.addEventListener("click", this.showNextImage.bind(this));
        document.addEventListener("keydown", this.handleKeyDown.bind(this));
    }

    #o() {
        this.overlay.removeEventListener("wheel", this.handleWheel.bind(this));
        this.imageWrapper.removeEventListener("mousedown", this.startDrag.bind(this));
        this.imageWrapper.removeEventListener("touchstart", this.handleTouchStart.bind(this));
        this.imageWrapper.removeEventListener("touchmove", this.handleTouchMove.bind(this));
        this.imageWrapper.removeEventListener("touchend", this.handleTouchEnd.bind(this));
        this.imageWrapper.removeEventListener("touchcancel", this.handleTouchEnd.bind(this));
        this.closeBtn.removeEventListener("click", this.closePreview.bind(this));
        this.rotateBtn.removeEventListener("click", this.rotateImage.bind(this));
        this.downloadBtn.removeEventListener("click", this.downloadImage.bind(this));
        this.prevBtn.removeEventListener("click", this.showPrevImage.bind(this));
        this.nextBtn.removeEventListener("click", this.showNextImage.bind(this));
        document.removeEventListener("keydown", this.handleKeyDown.bind(this));
    }

    #r() {
        this.overlay.addEventListener("mousemove", this.doDrag.bind(this));
        this.overlay.addEventListener("mouseup", this.endDrag.bind(this));
        this.overlay.addEventListener("mouseleave", this.endDrag.bind(this));
    }

    #a() {
        this.overlay.removeEventListener("mousemove", this.doDrag.bind(this));
        this.overlay.removeEventListener("mouseup", this.endDrag.bind(this));
        this.overlay.removeEventListener("mouseleave", this.endDrag.bind(this));
    }

    resetTransform() {
        this.currentScale = 1;
        this.currentRotation = 0;
        this.currentX = 0;
        this.currentY = 0;
        this.updateImageTransform();
    }

    updateImageTransform() {
        this.imageWrapper.style.transform = `translate(${this.currentX}px, ${this.currentY}px) rotate(${this.currentRotation}deg) scale(${this.currentScale})`;
    }

    showImageByIndex(e) {
        if (e < 0 || e >= this.imageList.length) return;
        this.currentIndex = e;
        const t = this.imageList[this.currentIndex];
        this.resetTransform();
        const i = t.dataset.highres;
        const n = t.src;
        const s = t.alt || "";

        this.#d(!0);
        this.previewImg.src = n;
        this.previewImg.alt = s;

        this.previewImg.onload = () => {
            this.#h(s);
            this.#l();
            this.#p();
            this.#d(!1);
            i && i !== n && this.#c(i);

            // --- 检测并应用移动端全屏 ---
            const isMobile = /Android|iPhone|iPad|iPod/.test(navigator.userAgent);
            if (isMobile) {
                this.overlay.classList.add('fullscreen-mobile');
            } else {
                this.overlay.classList.remove('fullscreen-mobile');
            }
            // ---------------------------------
        };

        this.previewImg.onerror = () => {
            this.loadingIndicator.textContent = "Failed to load image";
        };

        this.overlay.style.display = "flex";
        setTimeout(() => {
            this.overlay.classList.add('showing');
        }, 10);
        document.body.style.overflow = "hidden";
    }

    #c(e) {
        const t = new Image;
        t.onload = () => {
            this.previewImg.onload = null;
            this.previewImg.src = e;
            this.currentX = 0;
            this.currentY = 0;
            this.updateImageTransform();
            this.previewImg.style.opacity = "0.9";
            setTimeout(() => {
                this.previewImg.style.opacity = "1";
                this.previewImg.style.transition = "opacity 0.3s ease";
            }, 50);
        };
        t.onerror = () => {};
        t.src = e;
    }

    #d(e) {
        e ? (this.loadingIndicator.style.display = "block", this.imageWrapper.style.display = "none", this.imageInfo.style.display = "none", this.loadingIndicator.textContent = "Loading...") : (this.loadingIndicator.style.display = "none", this.imageWrapper.style.display = "block");
    }

    #h(e) {
        this.imageCaption.textContent = e;
        this.imageIndex.textContent = `${this.currentIndex + 1} / ${this.imageList.length}`;
        this.updateZoomInfo();
        this.imageInfo.style.display = e || this.imageList.length > 1 ? "block" : "none";
    }

    updateZoomInfo() {
        const zoomPercent = Math.round(this.currentScale * 100);
        this.imageZoom.textContent = `${zoomPercent}%`;
    }

    #p() {
        const resText = `${this.previewImg.naturalWidth} × ${this.previewImg.naturalHeight}`;
        this.imageResolution.textContent = resText;
    }

    #l() {
        this.prevBtn.disabled = this.currentIndex <= 0;
        this.nextBtn.disabled = this.currentIndex >= this.imageList.length - 1;
    }

    openPreview(e, t) {
        e.stopPropagation();
        const i = this.imageList.indexOf(t);
        -1 !== i && this.showImageByIndex(i);
    }

    closePreview() {
        this.overlay.classList.remove('showing');
        // --- 移除全屏类 ---
        this.overlay.classList.remove('fullscreen-mobile');
        // -------------------
        setTimeout(() => {
            this.overlay.style.display = "none";
        }, 250);
        document.body.style.overflow = "";
    }

    showNextImage() {
        this.currentIndex < this.imageList.length - 1 && this.showImageByIndex(this.currentIndex + 1);
    }

    showPrevImage() {
        this.currentIndex > 0 && this.showImageByIndex(this.currentIndex - 1);
    }

    handleKeyDown(e) {
        if ("flex" === this.overlay.style.display) {
            switch (e.key) {
                case "Escape":
                    this.closePreview();
                    break;
                case "ArrowRight":
                    this.showNextImage();
                    break;
                case "ArrowLeft":
                    this.showPrevImage();
            }
        }
    }

    handleWheel(e) {
        e.preventDefault();
        const rect = this.imageWrapper.getBoundingClientRect();
        const cursorX = e.clientX;
        const cursorY = e.clientY;
        const imgCenterX = rect.left + rect.width / 2;
        const imgCenterY = rect.top + rect.height / 2;
        const relX = cursorX - imgCenterX;
        const relY = cursorY - imgCenterY;
        const linearScaleFactor = 0.2;
        const scaleChange = e.deltaY > 0 ? -linearScaleFactor : linearScaleFactor;
        const oldScale = this.currentScale;
        let newScale = oldScale + scaleChange;
        newScale = Math.min(Math.max(newScale, this.config.minScale), this.config.maxScale);
        if (newScale !== oldScale) {
            const scaleRatio = newScale / oldScale;
            this.currentX -= relX * (scaleRatio - 1);
            this.currentY -= relY * (scaleRatio - 1);
            this.currentScale = newScale;
            this.updateImageTransform();
            this.updateZoomInfo();
        }
    }

    startDrag(e) {
        if (e.button === 0) {
            e.preventDefault();
            e.stopPropagation();
            this.isDragging = true;
            this.startX = e.clientX - this.currentX;
            this.startY = e.clientY - this.currentY;
            this.overlay.classList.add("dragging");
            this.#r();
        }
    }

    doDrag(e) {
        if (this.isDragging) {
            e.preventDefault();
            e.stopPropagation();
            this.currentX = e.clientX - this.startX;
            this.currentY = e.clientY - this.startY;
            this.updateImageTransform();
        }
    }

    endDrag(e) {
        if (this.isDragging) {
            if (e) e.stopPropagation();
            this.isDragging = false;
            this.overlay.classList.remove("dragging");
            this.#a();
        }
    }

    getPinchDistance(touches) {
        const dx = touches[0].clientX - touches[1].clientX;
        const dy = touches[0].clientY - touches[1].clientY;
        return Math.sqrt(dx * dx + dy * dy);
    }

    handleTouchStart(e) {
        e.preventDefault();
        this.touchStartCoords.x = [];
        this.touchStartCoords.y = [];
        for (let i = 0; i < e.touches.length; i++) {
            this.touchStartCoords.x[i] = e.touches[i].clientX;
            this.touchStartCoords.y[i] = e.touches[i].clientY;
        }
        if (e.touches.length === 1) {
            // --- 移除了 swipeStartX 和 swipeStartTime 相关代码 ---
            this.isDragging = true;
            this.startX = e.touches[0].clientX - this.currentX;
            this.startY = e.touches[0].clientY - this.currentY;
            this.overlay.classList.add("dragging");
            // -----------------------------------------------------
        } else if (e.touches.length >= 2) {
            this.isPinching = true;
            this.lastPinchDistance = this.getPinchDistance(e.touches);
        }
    }

    handleTouchMove(e) {
        e.preventDefault();
        if (e.touches.length === 1 && !this.isPinching) {
            if (this.isDragging) {
                this.currentX = e.touches[0].clientX - this.startX;
                this.currentY = e.touches[0].clientY - this.startY;
                this.updateImageTransform();
            }
        } else if (e.touches.length >= 2) {
            this.isPinching = true;
            const currentPinchDistance = this.getPinchDistance(e.touches);
            if (this.lastPinchDistance > 0) {
                const delta = currentPinchDistance - this.lastPinchDistance;
                const linearScaleFactor = 0.005;
                const scaleDelta = delta * linearScaleFactor;
                const oldScale = this.currentScale;
                let newScale = oldScale + scaleDelta;
                newScale = Math.min(Math.max(newScale, this.config.minScale), this.config.maxScale);
                if (newScale !== oldScale) {
                    const scaleRatio = newScale / oldScale;
                    const centerX = (e.touches[0].clientX + e.touches[1].clientX) / 2;
                    const centerY = (e.touches[0].clientY + e.touches[1].clientY) / 2;
                    const rect = this.imageWrapper.getBoundingClientRect();
                    const imgCenterX = rect.left + rect.width / 2;
                    const imgCenterY = rect.top + rect.height / 2;
                    const relX = centerX - imgCenterX;
                    const relY = centerY - imgCenterY;
                    this.currentX -= relX * (scaleRatio - 1);
                    this.currentY -= relY * (scaleRatio - 1);
                    this.currentScale = newScale;
                    this.updateImageTransform();
                    this.updateZoomInfo();
                }
            }
            this.lastPinchDistance = currentPinchDistance;
        }
    }

    handleTouchEnd(e) {
        e.preventDefault();
        if (e.touches.length === 0) {
            if (this.isDragging) {
                this.isDragging = false;
                this.overlay.classList.remove("dragging");
                // --- 移除了 handleSwipe 调用 ---
            }
            // --------------------------------
            if (this.isPinching) {
                this.isPinching = false;
                this.lastPinchDistance = 0;
            }
        } else if (e.touches.length === 1 && this.isPinching) {
            this.isPinching = false;
            this.lastPinchDistance = 0;
            this.isDragging = true;
            this.startX = e.touches[0].clientX - this.currentX;
            this.startY = e.touches[0].clientY - this.currentY;
            this.overlay.classList.add("dragging");
        }
    }

    // --- 移除了 handleSwipe 方法 ---
    // ------------------------------

    rotateImage() {
        this.currentRotation = (this.currentRotation + 90) % 360;
        this.updateImageTransform();
    }

    downloadImage() {
        const e = document.createElement("a");
        e.href = this.previewImg.src;
        const t = this.previewImg.alt.replace(/\s+/g, "_") || `image_${this.currentIndex + 1}`;
        e.download = `${t}.jpg`;
        document.body.appendChild(e);
        e.click();
        document.body.removeChild(e);
    }

    observeImages() {
        this.observer = new MutationObserver(e => {
            e.forEach(e => {
                e.addedNodes.forEach(e => {
                    let t = [];
                    if (e.tagName === "IMG" && e.matches(this.targetSelector)) {
                        t.push(e);
                    } else if (e.querySelectorAll) {
                        t = Array.from(e.querySelectorAll(this.targetSelector));
                    }
                    t.forEach(e => {
                        if (!this.imageList.includes(e)) {
                            this.imageList.push(e);
                            this.bindClickEvents([e]);
                        }
                    });
                });
                if (e.removedNodes.length > 0) {
                    this.imageList = this.imageList.filter(e => document.body.contains(e));
                }
            });
        });
        this.observer.observe(document.body, { childList: !0, subtree: !0 });
    }

    bindClickEvents(e) {
        e.forEach(e => {
            if (!e.dataset.imageViewerBound) {
                e.addEventListener("click", t => this.openPreview(t, e));
                e.dataset.imageViewerBound = "true";
                e.style.cursor = "pointer";
            }
        });
    }
}

customElements.define("image-viewer", e);

document.addEventListener("DOMContentLoaded", () => {
    if (!document.querySelector("image-viewer")) {
        const t = document.getElementById("gd-image-viewer");
        let i = {};
        if (t) {
            i.targetSelector = t.dataset.targetSelector || "img";
            i.maxScale = parseFloat(t.dataset.maxScale) || 5;
            i.minScale = parseFloat(t.dataset.minScale) || 0.5;
            i.allowRotate = t.dataset.allowRotate !== "false";
            i.allowDownload = t.dataset.allowDownload !== "false";
        } else {
            i.targetSelector = "img";
            i.maxScale = 5;
            i.minScale = 0.5;
            i.allowRotate = !0;
            i.allowDownload = !0;
        }
        const n = new e(i);
        document.body.appendChild(n);
    }
});